function minStack(data) {
    const tokens = (data || '').trim().split(/\s+/).filter(Boolean);
    if (!tokens.length) return 'None';

    const st = [];
    const mins = [];
    const out = [];

    let i = 0;
    while (i < tokens.length) {
        const op = tokens[i++];
        if (op === 'push' && i < tokens.length) {
            const v = parseInt(tokens[i++], 10);
            st.push(v);
            if (!mins.length || v <= mins[mins.length - 1]) mins.push(v);
        } else if (op === 'pop') {
            if (st.length) {
                const v = st.pop();
                if (mins.length && v === mins[mins.length - 1]) mins.pop();
            }
        } else if (op === 'top') {
            out.push(st.length ? String(st[st.length - 1]) : 'None');
        } else if (op === 'getMin') {
            out.push(mins.length ? String(mins[mins.length - 1]) : 'None');
        }
    }

    return out.length ? out.join(' ') : 'None';
}

